                    {p.p5 && <div style={{ fontSize: 13, color: 'rgba(255,255,255,0.9)' }}>₹{p.p5} <span style={{ fontSize: 10, color: 'rgba(255,255,255,0.3)' }}>/ 5ml</span></div>}
